const items = $input.all();
const sessionData = items[0]?.json;

let history = [];

if (sessionData && sessionData.conversation_history) {
  try {
    history = JSON.parse(sessionData.conversation_history);
    if (!Array.isArray(history)) history = [];
  } catch(e) {
    history = [];
  }
}

const userMessage = $('Telegram Trigger').item.json.message.text;
const chatId = String($('Telegram Trigger').item.json.message.chat.id);

return [{
  json: {
    history: history,
    userMessage: userMessage,
    chatId: chatId
  }
}];
